def shout(func):
    def wrapper():
        print(">>> Starting...")
        func()
        print("<<< Done!")
    return wrapper

@shout
def greet():
    print("Hi there!")

greet()

import functools, time

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        print(f"{func.__name__} took {time.time()-start:.4f}s")
        return result
    return wrapper
